// 伪代码：三层 ADC 架构接口定义

/* ========== Layer 1: Hardware Abstraction ========== */
typedef struct {
    ADC_HandleTypeDef hadc;
    uint32_t sampling_time;      // ADC_SAMPLETIME_7POINT5CYCLES 等
    uint32_t resolution;         // ADC_RESOLUTION_12B 等
    uint32_t trigger_source;     // ADC_EXTERNALTRIGCONV_T1_TRGO
    uint32_t dma_channel;        // DMA1_Channel1
} AdcHardwareConfig;

HAL_StatusTypeDef AdcHardware_Init(AdcHardwareConfig *cfg);
HAL_StatusTypeDef AdcHardware_StartDMA(AdcHardwareConfig *cfg, uint16_t *buf, uint32_t len);

/* ========== Layer 2: Signal Chain ========== */
typedef struct {
    uint16_t *ring_buffer;       // DMA 环形缓冲区
    uint32_t buffer_size;        // 必须是 2 的幂，如 256
    uint32_t filter_window;      // 移动平均窗口 N
    int32_t temp_comp_table[32]; // 温度补偿系数
} AdcSignalChain;

int32_t AdcSignalChain_Filter(AdcSignalChain *sc);
int32_t AdcSignalChain_TempCompensate(AdcSignalChain *sc, int32_t raw);

/* ========== Layer 3: Application ========== */
typedef struct {
    AdcSignalChain *chain;
    float vref_mv;               // 参考电压，如 3300mV
    float sensor_scale;          // 传感器缩放系数
} AdcAppContext;

float AdcApp_GetVoltage(AdcAppContext *ctx);
float AdcApp_GetTemperature(AdcAppContext *ctx);

/* DMA 环形缓冲区 + 移动平均滤波，STM32F103 */
#define ADC_BUF_SIZE    256
#define AVG_WINDOW      16

static volatile uint16_t adc_dma_buf[ADC_BUF_SIZE];
static uint32_t adc_write_idx = 0;

/* 移动平均滤波器状态 */
typedef struct {
    int32_t buffer[AVG_WINDOW];
    uint8_t head;  /* 写入位置 */
    uint8_t count; /* 当前有效数据个数 */
    int32_t sum;   /* 当前窗口总和 */
} MovingAvgFilter;

static MovingAvgFilter sma;

/* 初始化移动平均滤波器 */
void MovingAvg_Init(MovingAvgFilter *f) {
    memset(f->buffer, 0, sizeof(f->buffer));
    f->head = 0;
    f->count = 0;
    f->sum = 0;
}

/* 输入一个新样本，返回滤波结果 */
/* 有效数据 < WINDOW 时返回部分平均值 */
int32_t MovingAvg_Push(MovingAvgFilter *f, uint16_t sample) {
    uint8_t tail;

    if (f->count == AVG_WINDOW) {
        /* 窗口已满：移除最旧的样本 */
        tail = (f->head + AVG_WINDOW - 1) & (AVG_WINDOW - 1);
        f->sum -= f->buffer[tail];
    } else {
        f->count++;
    }

    /* 写入新样本 */
    f->buffer[f->head] = sample;
    f->sum += sample;
    f->head = (f->head + 1) & (AVG_WINDOW - 1);

    return f->sum / f->count;
}

/* DMA 半传输/全传输回调：合并两半数据 */
void HAL_DMA HalfCpltCallback(DMA_HandleTypeDef *hdma) {
    uint32_t half = ADC_BUF_SIZE / 2;
    for (uint32_t i = 0; i < half; i++) {
        MovingAvg_Push(&sma, adc_dma_buf[i]);
    }
    adc_write_idx = half;
}

void HAL_DMA_CpltCallback(DMA_HandleTypeDef *hdma) {
    uint32_t half = ADC_BUF_SIZE / 2;
    for (uint32_t i = half; i < ADC_BUF_SIZE; i++) {
        MovingAvg_Push(&sma, adc_dma_buf[i]);
    }
    adc_write_idx = 0;
}

/* 主循环中读取滤波结果 */
int32_t GetFilteredValue(void) {
    if (sma.count == 0) return -1; /* 无数据 */
    return (sma.sum + sma.count / 2) / sma.count; /* 四舍五入 */
}

/* 陷阱演示：错误配置导致的通道交叉 */

/* 错误配置：缓冲区大小 = 通道数 * 采样数，但开发者只写了采样数 */
#define NUM_CHANNELS    3
#define SAMPLES_PER_CYCLE 64

/* ❌ 错误：缓冲区应该为 NUM_CHANNELS * SAMPLES_PER_CYCLE = 192 */
static uint16_t adc_buf_wrong[SAMPLES_PER_CYCLE];  /* 只有 64，不够！ */

/* ✅ 正确：缓冲区大小 = 通道数 × 采样数 */
static uint16_t adc_buf_correct[NUM_CHANNELS * SAMPLES_PER_CYCLE];

/* VREF 未校准的温度读取 */
float ReadTemperature_UnCalibrated(void) {
    /* 直接使用 ADC 原始值，假设 VREF = 3.3V 精确不变 */
    uint16_t raw = adc_buf_correct[0];  /* 假设通道 0 接温度传感器 */
    float voltage = raw * 3.3f / 4095.0f;  /* VREF 波动 10mV 直接引入误差 */
    return (voltage - 0.76f) / 0.0025f + 25.0f;  /* STM32 片上温度传感器公式 */
}

/* 使用 VREFINT 校准的读取 */
float ReadTemperature_Calibrated(void) {
    extern uint16_t vrefint_cal;  /* 出厂校准值，存储在 OTP 中 */
    extern uint16_t vrefint_measure;  /* 实时测量的 VREFINT 值 */

    /* 实时计算实际 VREF */
    float actual_vref = 3.3f * vrefint_cal / vrefint_measure;

    uint16_t raw = adc_buf_correct[0];
    float voltage = raw * actual_vref / 4095.0f;
    return (voltage - 0.76f) / 0.0025f + 25.0f;
}

/* ========== 改进前：坏味道的裸机轮询 ========== */
/* 问题：魔法数字、函数过长、全局状态、阻塞等待、无滤波 */

uint16_t adc_value;

void ReadAndProcessADC(void) {
    // 魔法数字散落在各处
    ADC->CR2 |= ADC_CR2_SWSTART;  // 启动转换
    while(!(ADC->SR & ADC_SR_EOC));  // 阻塞等待
    adc_value = ADC->DR;  // 读取原始值

    // 直接在业务逻辑中使用，没有任何滤波
    float voltage = adc_value * 3.3 / 4095.0;  // 魔法数字
    if (voltage > 2.5) {
        GPIOB->BSRR = GPIO_BSRR_BS8;  // 打开继电器
    } else {
        GPIOB->BSRR = GPIO_BSRR_BR8;  // 关闭继电器
    }
}

/* ========== 改进后：DMA + 滤波 + 封装 ========== */

#include <stdint.h>
#include <string.h>

#define ADC_RESOLUTION      4095U
#define ADC_VREF_NOMINAL_MV 3300U
#define ADC_FILTER_WINDOW   16
#define ADC_BUF_SIZE        256

typedef struct {
    uint16_t dma_buf[ADC_BUF_SIZE];
    uint32_t buf_len;
    int32_t filter_sum;
    uint8_t filter_count;
    uint16_t filter_buf[ADC_FILTER_WINDOW];
    uint8_t filter_head;
    uint16_t vref_mv;  /* 校准后的参考电压 */
} AdcChannel;

/* 初始化 ADC 通道（信息隐藏：使用者不需要知道 DMA 细节）*/
void AdcChannel_Init(AdcChannel *ch) {
    memset(ch, 0, sizeof(*ch));
    ch->vref_mv = ADC_VREF_NOMINAL_MV;
    ch->filter_sum = 0;
    ch->filter_count = 0;
    ch->filter_head = 0;
}

/* 内部：移动平均（不对外暴露）*/
static int32_t _FilterPush(AdcChannel *ch, uint16_t sample) {
    if (ch->filter_count == ADC_FILTER_WINDOW) {
        uint8_t tail = (ch->filter_head + ADC_FILTER_WINDOW - 1)
                       & (ADC_FILTER_WINDOW - 1);
        ch->filter_sum -= ch->filter_buf[tail];
    } else {
        ch->filter_count++;
    }
    ch->filter_buf[ch->filter_head] = sample;
    ch->filter_sum += sample;
    ch->filter_head = (ch->filter_head + 1)
                      & (ADC_FILTER_WINDOW - 1);
    return ch->filter_sum / ch->filter_count;
}

/* 外部接口：获取滤波后的电压值（mV）*/
uint32_t AdcChannel_GetVoltage_mV(AdcChannel *ch) {
    if (ch->filter_count == 0) return 0;
    int32_t filtered = ch->filter_sum / ch->filter_count;
    return (uint32_t)(filtered * ch->vref_mv / ADC_RESOLUTION);
}

/* DMA 回调：在回调中只做数据搬运，不做滤波（避免中断风暴）*/
void HAL_DMA_CpltCallback(DMA_HandleTypeDef *hdma) {
    extern AdcChannel temp_ch;  /* 实际项目中用数组管理多个通道 */
    for (uint32_t i = 0; i < ADC_BUF_SIZE; i++) {
        _FilterPush(&temp_ch, hdma->Instance->CNDTR ? 0 : 0);
        /* 实际实现应从 DMA 缓冲区读取 adc_dma_buf[i] */
    }
}

/* 重构的收益：
 * - 魔法数字消失：ADC_RESOLUTION, ADC_VREF_NOMINAL_MV
 * - 单一职责：AdcChannel_GetVoltage_mV 只做一件事
 * - 信息隐藏：_FilterPush 是 static，外部不可见
 * - 非阻塞：DMA 自动搬运，CPU 可以做别的事
 * - 精度提升：移动平均滤波消除高频噪声
 * - 代价：增加了约 200 字节 RAM（缓冲区 + 滤波器状态）
 */
